24	    },
25	  });
26	
27	  const exitCode = await proc.exited;
28	  const stdout = await new Response(proc.stdout).text();
29	  const stderr = await new Response(proc.stderr).text();
30	
31	  if (exitCode !== 0) {
32	    const stderrMessage = stderr.trim();
33	    const failureReason =
34	      proc.killed && proc.signalCode
35	        ? `terminated by ${proc.signalCode}${stderrMessage ? `: ${stderrMessage}` : ` after ${timeoutMs}ms timeout`}`
36	        : stderrMessage;
37	
38	    throw new GitError(`git ${args.join(" ")} failed: ${failureReason}`);
39	  }
40	
41	  return stdout.trim();
42	}
